<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Sorting Algorithm Visualizer</title>
    <style>
        body {
            font-family: sans-serif;
            background-color: #1e1e2e;
            color: #cdd6f4;
            padding: 20px;
            display: flex;
            flex-direction: column;
            align-items: center;
        }

        h1 {
            color: #89b4fa;
            margin-bottom: 30px;
        }

        #controls {
            margin-bottom: 30px;
            display: flex;
            gap: 15px;
        }

        button {
            padding: 10px 20px;
            font-size: 16px;
            cursor: pointer;
            border: none;
            border-radius: 8px;
            transition: background-color 0.2s, transform 0.1s;
            background-color: #45475a;
            color: white;
        }

        button:hover {
            background-color: #585b70;
        }

        button:active {
            transform: scale(0.98);
        }

        #bars {
            display: flex;
            align-items: flex-end; /* Bars grow from the bottom */
            height: 400px;
            width: 100%;
            border-bottom: 2px solid #585b70;
            padding: 5px;
            box-sizing: border-box;
        }

        .bar {
            flex-grow: 1; /* Distribute space evenly */
            background-color: #a6adc8;
            margin: 0 1px;
            transition: height 0.3s ease, background-color 0.2s;
            min-width: 1px; /* Ensure bars are visible even if array is large */
        }

        /* Highlighting classes for visualization feedback */
        .comparing {
            background-color: #f5e0dc !important; /* Light red/pink highlight */
        }

        .swapping {
            background-color: #b4c2ff !important; /* Blue highlight */
        }

    </style>
</head>
<body>

    <h1>Sorting Algorithm Visualizer</h1>

    <div id="controls">
        <button id="sort">Start Sort</button>
        <button id="shuffle">Shuffle</button>
        <button id="reset">Reset</button>
    </div>

    <div id="bars">
        <!-- Bars will be injected here -->
    </div>

    <script>
        // --- Global State and Initialization ---
        let currentArray = [];
        const MAX_VALUE = 400; // Max height for scaling (matches CSS height)
        const BAR_CONTAINER = document.getElementById('bars');

        /**
         * Renders the current state of the array into DOM elements.
         * @param {number[]} arr - The array to render.
         */
        function renderBars(arr) {
            BAR_CONTAINER.innerHTML = ''; // Clear existing bars
            const barWidthRatio = 1 / arr.length;

            arr.forEach((value, index) => {
                const bar = document.createElement('div');
                bar.className = 'bar';
                // Height is proportional to value (scaled by MAX_VALUE)
                bar.style.height = `${(value / Math.max(...currentArray)) * 100}%`;
                // We use flex-grow: 1 in CSS, so we just set the height based on percentage of container
                // For simplicity and robustness against scaling issues, let's stick to setting explicit heights relative to MAX_VALUE if possible, but using percentages is safer with flexbox.
                bar.style.flexBasis = `${barWidthRatio * 100}%`; // Ensure even distribution
                bar.style.height = `${(value / Math.max(...currentArray)) * 95 + 5}%`; // Add a little padding/base height
                bar.dataset.index = index;
                BAR_CONTAINER.appendChild(bar);
            });
        }

        /**
         * Initializes the visualization state and renders the initial bars.
         */
        function initializeVisualization() {
            // Default starting array (e.g., 1 to 20)
            currentArray = Array.from({ length: 25 }, (_, i) => Math.floor(Math.random() * 30) + 5);
            renderBars(currentArray);
        }


        // --- Sorting Logic (Bubble Sort implementation for step-by-step control) ---

        /**
         * The state machine for the sorting algorithm.
         * We use Bubble Sort because it is easy to define clear comparison/swap steps.
         */
        let sortState = {
            arr: [],
            n: 0,
            i: 0, // Outer loop index (passes)
            j: 0, // Inner loop index (comparisons)
            swapped: false,
            isSorting: false
        };

        /**
         * Performs one step of the Bubble Sort algorithm.
 * @returns {boolean} True if fully sorted, False otherwise.
 */
        function bubbleSortStep() {
            if (!sortState.isSorting) return false;

            const arr = sortState.arr;
            const n = sortState.n;
            let swapped = false;

            // Outer loop (passes): i goes from 0 to n-2
            while (sortState.i < n - 1 && !sortState.swapped) {
                // Inner loop (comparisons): j goes from 0 to n-1-i-1
                let j = sortState.j;

                // Reset state for the current pass if we finished a comparison block
                if (j >= n - 1 - sortState.i && !sortState.swapped) {
                    sortState.i++;
                    sortState.j = 0;
                    continue; // Restart inner loop check
                }

                // Check bounds for the current step
                if (j >= n - 1 - sortState.i) {
                     // This pass is complete, move to next outer iteration
                    sortState.i++;
                    sortState.j = 0;
                    continue;
                }


                // --- Step: Comparison ---
                const idxA = j;
                const idxB = j + 1;

                // Highlight comparison elements
                document.querySelectorAll('.bar').forEach(el => el.classList.remove('comparing', 'swapping'));
                document.querySelector(`[data-index="${idxA}"]`).classList.add('comparing');
                document.querySelector(`[data-index="${idxB}"]`).classList.add('comparing');

                // Check condition: if arr[j] > arr[j+1], swap them
                if (arr[idxA] > arr[idxB]) {
                    // --- Step: Swap ---
                    swapped = true;
                    [arr[idxA], arr[idxB]] = [arr[idxB], arr[idxA]];

                    // Update visualization immediately after swap
                    renderBars(arr);

                    // Highlight swapped elements
                    document.querySelector(`[data-index="${idxA}"]`).classList.add('swapping');
                    document.querySelector(`[data-index="${idxB}"]`).classList.add('swapping');
                } else {
                     // No swap, just update visualization (optional: reset highlights)
                     renderBars(arr);
                }

                // Advance state for the next step
                sortState.j++;
            }


            // Check termination condition
            if (!swapped && sortState.i >= n - 1) {
                 // If no swaps occurred in a full pass, it's sorted.
                 return true;
            }

            // Update state for the next call
            sortState.swapped = swapped;
            return false; // Not fully sorted yet
        }


        // --- API Implementation (window.viz) ---

        /**
         * @returns {number[]} The current array state.
         */
        window.viz.array = function() {
            return [...currentArray];
        };

        /**
         * Sets the internal array state and redraws the visualization.
         * @param {number[]} a - The new array of numbers.
         */
        window.viz.setArray = function(a) {
            if (!Array.isArray(a)) return;
            currentArray = [...a];
            renderBars(currentArray);
        };

        /**
         * Advances the sorting algorithm by one step.
 * @returns {boolean} True if fully sorted, false otherwise.
 */
        window.viz.sortStep = function() {
            if (!sortState.isSorting) {
                // Initialize sort state on first call
                sortState.arr = [...currentArray];
                sortState.n = currentArray.length;
                sortState.i = 0;
                sortState.j = 0;
                sortState.swapped = true; // Force the first pass
                sortState.isSorting = true;
            }

            const isSorted = bubbleSortStep();

            if (isSorted) {
                // Final cleanup: ensure all bars are stable and unhighlighted
                document.querySelectorAll('.bar').forEach(el => el.classList.remove('comparing', 'swapping'));
                sortState.isSorting = false;
            }

            return isSorted;
        };

        /**
         * Checks if the current array state is sorted ascendingly.
 * @returns {boolean} True if sorted, False otherwise.
 */
        window.viz.sorted = function() {
            for (let i = 0; i < currentArray.length - 1; i++) {
                if (currentArray[i] > currentArray[i + 1]) {
                    return false;
                }
            }
            return true;
        };


        // --- Event Handlers and Setup ---

        /**
         * Shuffles the current array.
         */
        function handleShuffle() {
            const arr = [...currentArray];
            for (let i = arr.length - 1; i > 0; i--) {
                const j = Math.floor(Math.random() * (i + 1));
                [arr[i], arr[j]] = [arr[j], arr[i]];
            }
            window.viz.setArray(arr);
        }

        /**
         * Resets the visualization to a new random state.
         */
        function handleReset() {
             // Reset internal sort state machine
            sortState = {
                arr: [],
                n: 0,
                i: 0,
                j: 0,
                swapped: false,
                isSorting: false
            };

            handleShuffle(); // Just shuffle to get a new starting point
        }

        // Attach event listeners
        document.getElementById('shuffle').addEventListener('click', handleShuffle);
        document.getElementById('reset').addEventListener('click', handleReset);
        document.getElementById('sort').addEventListener('click', () => {
            if (window.viz.sorted()) {
                alert("The array is already sorted!");
                return;
            }

            // Disable buttons during sorting animation
            document.getElementById('shuffle').disabled = true;
            document.getElementById('reset').disabled = true;
            document.getElementById('sort').disabled = true;

            let stepsTaken = 0;
            const intervalId = setInterval(() => {
                const isFinished = window.viz.sortStep();
                stepsTaken++;

                if (isFinished) {
                    clearInterval(intervalId);
                    // Re-enable buttons and ensure final state cleanup
                    document.getElementById('shuffle').disabled = false;
                    document.getElementById('reset').disabled = false;
                    document.getElementById('sort').disabled = true; // Keep disabled after completion
                }

            }, 100); // Animation speed (ms per step)
        });


        // Initial setup call
        initializeVisualization();

    </script>
</body>
</html>
